import React, { useState, useEffect } from 'react';

const ProductForm = ({ onAdd, onUpdate, editingProduct, onCancel }) => {
  const [form, setForm] = useState({ name: '', category: '', quantity: '', price: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const isEditing = !!editingProduct;

  useEffect(() => {
    if (editingProduct) {
      setForm({
        name: editingProduct.name,
        category: editingProduct.category,
        quantity: editingProduct.quantity,
        price: editingProduct.price,
      });
    } else {
      setForm({ name: '', category: '', quantity: '', price: '' });
    }
  }, [editingProduct]);

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async e => {
    e.preventDefault();
    setError('');
    if (!form.name || !form.category || form.quantity === '' || form.price === '') {
      setError('All fields are required.');
      return;
    }
    setLoading(true);
    try {
      const data = { ...form, quantity: Number(form.quantity), price: Number(form.price) };
      if (isEditing) {
        await onUpdate(editingProduct._id, data);
      } else {
        await onAdd(data);
        setForm({ name: '', category: '', quantity: '', price: '' });
      }
    } catch {
      setError('Something went wrong. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="form-card">
      <h2 className="form-title">{isEditing ? '✏️ Edit Product' : '➕ Add New Product'}</h2>
      <p className="form-sub">
        {isEditing ? `Editing: ${editingProduct.name}` : 'Fill in the details to add a new product.'}
      </p>
      {error && <div className="form-error">⚠️ {error}</div>}
      <form onSubmit={handleSubmit}>
        <div className="form-grid">
          <div className="form-field">
            <label className="form-label">Product Name</label>
            <input name="name" value={form.name} onChange={handleChange} placeholder="e.g. Wireless Mouse" className="form-input" />
          </div>
          <div className="form-field">
            <label className="form-label">Category</label>
            <input name="category" value={form.category} onChange={handleChange} placeholder="e.g. Electronics" className="form-input" />
          </div>
          <div className="form-field">
            <label className="form-label">Quantity</label>
            <input name="quantity" type="number" value={form.quantity} onChange={handleChange} placeholder="e.g. 50" min="0" className="form-input" />
          </div>
          <div className="form-field">
            <label className="form-label">Price ($)</label>
            <input name="price" type="number" value={form.price} onChange={handleChange} placeholder="e.g. 29.99" min="0" step="0.01" className="form-input" />
          </div>
        </div>
        <div className="form-actions">
          <button type="submit" className="submit-btn" disabled={loading}>
            {loading ? 'Saving...' : isEditing ? '✏️ Update Product' : '➕ Add Product'}
          </button>
          {isEditing && (
            <button type="button" className="cancel-btn" onClick={onCancel}>Cancel</button>
          )}
        </div>
      </form>
    </div>
  );
};

export default ProductForm;
